// shadcn
import { Button } from "@/components/ui/button";
import { SidebarProvider, SidebarTrigger } from "@/components/ui/sidebar";

// project
import NotificationDropdown from "@/components/uiable/layout/notification-dropdown";
import SearchBar from "@/components/uiable/layout/search-bar";
import UserProfile from "@/components/uiable/layout/user-profile";

// assets
import { Settings } from "lucide-react";

//  ------------------------------ | LAYOUT - DASHBOARD | ------------------------------  //

export default function Navbar2() {
  return (
    <SidebarProvider className="min-h-fit w-full">
      <header className="sticky top-0 z-40 flex h-16 w-full shrink-0 items-center gap-1 bg-background/80 backdrop-blur-md px-4 sm:px-6">
        <SidebarTrigger className="-ml-1 w-11 h-11 rounded-lg relative flex items-center justify-center mx-1" />
        <SearchBar />
        <div className="flex-1" />
        <div className="flex items-center gap-2 sm:gap-4">
          <Button
            variant="ghost"
            size="icon"
            className="inline-flex items-center justify-center h-9 w-9 rounded-lg border border-transparent text-muted-foreground hover:bg-muted hover:text-primary transition-colors"
          >
            <Settings className="size-5" />
          </Button>
          <div className="h-4 w-px bg-border mx-1" />
          <NotificationDropdown />
          <div className="h-4 w-px bg-border mx-1" />
          <UserProfile />
        </div>
      </header>
    </SidebarProvider>
  );
}
